222		mode64, err := strconv.ParseUint(args[0], 8, 32)
223		if err != nil || fs.FileMode(mode64).Perm() != fs.FileMode(mode64) {
224			ts.Fatalf("invalid mode: %s", args[0])
225		}
226		if runtime.GOOS == "windows" {
227			return
228		}
229		fileInfo, err := os.Stat(ts.MkAbs(args[1]))
230		if err != nil {
231			ts.Fatalf("%s: %v", args[1], err)
232		}
233		equal := fileInfo.Mode().Perm() == fs.FileMode(mode64)&^chezmoitest.Umask
234		if neg && equal {
235			ts.Fatalf("%s unexpectedly has mode %03o", args[1], fileInfo.Mode().Perm())
236		}
237		if !neg && !equal {
238			format := "%s has mode %03o, expected %03o"
239			ts.Fatalf(format, args[1], fileInfo.Mode().Perm(), fs.FileMode(mode64)&^chezmoitest.Umask)
240		}
241	}
