463	// cmdMkGPGConfig creates a GPG key and a chezmoi configuration file.
464	func cmdMkGPGConfig(ts *testscript.TestScript, neg bool, args []string) {
465		if neg {
466			ts.Fatalf("unsupported: ! mkgpgconfig")
467		}
468		if len(args) > 1 || len(args) == 1 && args[0] != "-symmetric" {
469			ts.Fatalf("usage: mkgpgconfig [-symmetric]")
470		}
471		symmetric := len(args) == 1 && args[0] == "-symmetric"
472	
473		// Create a new directory for GPG. We can't use a subdirectory of the
474		// testscript's working directory because on darwin the absolute path can
475		// exceed GPG's limit of sockaddr_un.sun_path (107 characters, see man
476		// unix(7)). The limit exists because GPG creates a UNIX domain socket in
477		// its home directory and UNIX domain socket paths are limited to
478		// sockaddr_un.sun_path characters.
479		gpgHomeDir, err := os.MkdirTemp("", "test-gpg-homedir")
480		ts.Check(err)
481		ts.Defer(func() {
482			os.RemoveAll(gpgHomeDir)
483		})
484		if runtime.GOOS != "windows" {
485			ts.Check(os.Chmod(gpgHomeDir, 0o700))
486		}
487	
488		command, err := chezmoi.LookPath("gpg")
489		ts.Check(err)
490	
491		key, passphrase, err := chezmoitest.GPGGenerateKey(command, gpgHomeDir)
492		ts.Check(err)
493	
494		configFile := filepath.Join(ts.Getenv("HOME"), ".config", "chezmoi", "chezmoi.toml")
495		ts.Check(os.MkdirAll(filepath.Dir(configFile), fs.ModePerm))
496		lines := []string{
497			`encryption = "gpg"`,
498			`[gpg]`,
499			`    args = [`,
500			`        "--homedir", ` + strconv.Quote(gpgHomeDir) + `,`,
501			`        "--no-tty",`,
502			`        "--passphrase", ` + strconv.Quote(passphrase) + `,`,
503			`        "--pinentry-mode", "loopback",`,
504			`    ]`,
505		}
506		if symmetric {
507			lines = append(lines, `    symmetric = true`)
508		} else {
509			lines = append(lines, `    recipient = "`+key+`"`)
510		}
511		ts.Check(writeNewFile(configFile, []byte(chezmoitest.JoinLines(lines...)), 0o666))
512	}
