601	// cmdMockCommand creates a mock command from a definition.
602	func cmdMockCommand(ts *testscript.TestScript, neg bool, args []string) {
603		if neg {
604			ts.Fatalf("unsupported: ! mockcommand")
605		}
606		if len(args) != 1 {
607			ts.Fatalf("usage: mockcommand command")
608		}
609	
610		command := ts.MkAbs(args[0])
611		definitionYAML, err := os.ReadFile(command + ".yaml")
612		ts.Check(err)
613	
614		// Parse the definition.
615		type response struct {
616			Args                string            `yaml:"args"`
617			OrArgs              []string          `yaml:"orArgs"`
618			WindowsArgs         string            `yaml:"windowsArgs"`
619			RequireEnv          map[string]string `yaml:"requireEnv"`
620			Response            string            `yaml:"response"`
621			Destination         string            `yaml:"destination"`
622			EscapeChars         bool              `yaml:"escapeChars"`
623			SuppressLastNewline bool              `yaml:"suppressLastNewline"`
624			ExitCode            int               `yaml:"exitCode"`
625		}
626		var definition struct {
627			Responses []response `yaml:"responses"`
628			Default   response   `yaml:"default"`
629		}
630		ts.Check(chezmoi.FormatYAML.Unmarshal(definitionYAML, &definition))
631	
632		// Parse the mock command template.
633		var templateName, templateText string
634		var renderResponseFunc func(response) string
635		switch runtime.GOOS {
636		case "windows":
637			templateName = "mockcommand.cmd.tmpl"
638			templateText = mockcommandCmdTmplText
639			escapeCharsRx := regexp.MustCompile(`[\\&|><^]`)
640			escapeChars := func(s string) string {
641				return escapeCharsRx.ReplaceAllString(s, "^$0")
642			}
643			renderResponseFunc = func(r response) string {
644				var builder strings.Builder
645				for _, key := range slices.Sorted(maps.Keys(r.RequireEnv)) {
646					value := r.RequireEnv[key]
647					fmt.Fprintf(&builder, "    IF NOT \"%%%s%%\" == \"%s\" (\n", key, value)
648					fmt.Fprintf(&builder, "        echo.%s=%%%s%%, expected %s\n", key, key, value)
649					fmt.Fprint(&builder, "        exit /b 1\n")
650					fmt.Fprint(&builder, "    )\n")
651				}
652				var redirect string
653				if r.Destination == "stderr" {
654					redirect = " 1>&2"
655				}
656				lines := strings.Split(strings.TrimSuffix(r.Response, "\n"), "\n")
657				for i, line := range lines {
658					if r.EscapeChars {
659						line = escapeChars(line)
660					}
661					if r.SuppressLastNewline && i == len(lines)-1 {
662						fmt.Fprintf(&builder, "    echo | set /p=%s%s\n", line, redirect)
663					} else {
664						fmt.Fprintf(&builder, "    echo.%s%s\n", line, redirect)
665					}
666				}
667				fmt.Fprintf(&builder, "    exit /b %d", r.ExitCode)
668				return builder.String()
669			}
670		default:
671			templateName = "mockcommand.tmpl"
672			templateText = mockcommandTmplText
673			renderResponseFunc = func(r response) string {
674				var builder strings.Builder
675				for _, key := range slices.Sorted(maps.Keys(r.RequireEnv)) {
676					value := r.RequireEnv[key]
677					fmt.Fprintf(&builder, "    if [ \"${%s}\" != \"%s\" ]; then\n", key, value)
678					fmt.Fprintf(&builder, "        echo \"%s=${%s}, expected %s\"\n", key, key, value)
679					fmt.Fprint(&builder, "        exit 1\n")
680					fmt.Fprint(&builder, "    fi\n")
681				}
682				var redirect string
683				if r.Destination == "stderr" {
684					redirect = " 1>&2"
685				}
686				if strings.Contains(r.Response, "\n") {
687					fmt.Fprintf(&builder, "    cat%s <<EOF\n%sEOF\n", redirect, r.Response)
688				} else {
689					fmt.Fprintf(&builder, "    echo %q%s\n", r.Response, redirect)
690				}
691				fmt.Fprintf(&builder, "    exit %d", r.ExitCode)
692				return builder.String()
693			}
694		}
695		tmpl, err := template.New(templateName).Funcs(template.FuncMap{
696			"default": func(def, s string) string {
697				if s == "" {
698					return def
699				}
700				return s
701			},
702			"quote":          strconv.Quote,
703			"renderResponse": renderResponseFunc,
704			"replaceAll": func(old, new, s string) string { //nolint:predeclared,revive
705				return strings.ReplaceAll(s, old, new)
706			},
707		}).Parse(templateText)
708		ts.Check(err)
709	
710		// Create the mock command contents.
711		buffer := bytes.NewBuffer(make([]byte, 0, 1024))
712		ts.Check(tmpl.Execute(buffer, definition))
713		data := buffer.Bytes()
714		if runtime.GOOS == "windows" {
715			data = bytes.ReplaceAll(data, []byte("\n"), []byte("\r\n"))
716		}
717	
718		// Write the mock command.
719		switch runtime.GOOS {
720		case "windows":
721			ts.Check(os.WriteFile(ts.MkAbs(command+".cmd"), data, 0o666))
722		default:
723			ts.Check(os.WriteFile(ts.MkAbs(command), data, 0o777))
724		}
725	}
