783			ts.Fatalf("usage: removeline file line")
784		}
785		filename := ts.MkAbs(args[0])
786		data, err := os.ReadFile(filename)
787		ts.Check(err)
788		lineSlice := []byte(args[1])
789		lines := bytes.Split(data, []byte{'\n'})
790		n := 0
791		for _, line := range lines {
792			if bytes.Equal(line, lineSlice) {
793				continue
794			}
795			lines[n] = line
796			n++
797		}
798		if n == len(lines) {
799			ts.Fatalf("removeline: %q not found in %s", args[1], args[0])
800		}
801		data = append(bytes.Join(lines[:n], []byte{'\n'}), '\n')
802		ts.Check(os.WriteFile(filename, data, 0o666))
803	}
804	
805	// cmdRmDir removes directories.
806	func cmdRmDir(ts *testscript.TestScript, neg bool, args []string) {
807		if neg {
808			ts.Fatalf("unsupported: ! rmdir")
809		}
810		if len(args) < 1 {
811			ts.Fatalf("usage: rmdir paths...")
812		}
