854	// cmdUNIX2DOS converts files from UNIX line endings to DOS line endings.
855	func cmdUNIX2DOS(ts *testscript.TestScript, neg bool, args []string) {
856		if neg {
857			ts.Fatalf("unsupported: ! unix2dos")
858		}
859		if len(args) < 1 {
860			ts.Fatalf("usage: unix2dos paths...")
861		}
862		for _, arg := range args {
863			filename := ts.MkAbs(arg)
864			data, err := os.ReadFile(filename)
865			ts.Check(err)
866			dosData, err := unix2DOS(data)
867			ts.Check(err)
868			if err := os.WriteFile(filename, dosData, 0o666); err != nil {
869				ts.Fatalf("%s: %v", filename, err)
870			}
871		}
872	}
873	
874	// goosCondition evaluates cond as a logical OR of GOARCHes or GOOSes enclosed
875	// in parentheses, returning true if any of them match.
876	func goosCondition(cond string) (result, valid bool) {
877		// Interpret the condition as a logical OR of terms in parentheses.
878		if !strings.HasPrefix(cond, "(") || !strings.HasSuffix(cond, ")") {
879			result = false
880			valid = false
881			return result, valid
882		}
883		cond = strings.TrimPrefix(cond, "(")
884		cond = strings.TrimSuffix(cond, ")")
885		terms := strings.Split(cond, "||")
886	
887		// If any of the terms are neither known GOOSes nor GOARCHes then reject the
888		// condition as invalid.
889		for _, term := range terms {
890			if term == "unix" {
891				continue
892			}
893			if _, ok := imports.KnownOS[term]; !ok {
894				if _, ok := imports.KnownArch[term]; !ok {
895					valid = false
896					return result, valid
897				}
898			}
899		}
900	
901		// At this point, we know the expression is valid.
902		valid = true
903	
904		// If any of the terms match either runtime.GOOS or runtime.GOARCH then
905		// the condition is true.
906		for _, term := range terms {
907			switch {
908			case term == runtime.GOOS || term == "unix" && imports.UnixOS[runtime.GOOS]:
909				result = true
910				return result, valid
911			case term == runtime.GOARCH:
912				result = true
913				return result, valid
914			}
915		}
916	
917		// Otherwise, the condition is false.
918		result = false
919		return result, valid
920	}
921	
922	func prependDirToPath(dir, pathStr string) string {
923		return strings.Join(append([]string{dir}, filepath.SplitList(pathStr)...), string(os.PathListSeparator))
924	}
925	
926	func setup(env *testscript.Env) error {
927		var (
928			binDir  = filepath.Join(env.WorkDir, "bin")
929			homeDir = filepath.Join(env.WorkDir, "home", "user")
930		)
931	
932		absHomeDir, err := filepath.Abs(homeDir)
933		if err != nil {
934			return err
935		}
936		absSlashHomeDir := filepath.ToSlash(absHomeDir)
937	
938		env.Setenv("HOME", homeDir)
939		env.Setenv("PATH", prependDirToPath(binDir, env.Getenv("PATH")))
940		if runtime.GOOS == "windows" {
941			env.Setenv("PATHEXT", ".COM;.EXE;.BAT;.CMD;.VBS;.VBE;.JS;.JSE;.WSF;.WSH;.MSC;.CPL")
942		}
943		env.Setenv("CHEZMOICACHEDIR", path.Join(absSlashHomeDir, ".cache", "chezmoi"))
944		env.Setenv("CHEZMOICONFIGDIR", path.Join(absSlashHomeDir, ".config", "chezmoi"))
945		env.Setenv("CHEZMOISOURCEDIR", path.Join(absSlashHomeDir, ".local", "share", "chezmoi"))
946		env.Setenv("CHEZMOI_GITHUB_TOKEN", os.Getenv("CHEZMOI_GITHUB_TOKEN"))
947	
948		switch runtime.GOOS {
949		case "windows":
950			env.Setenv("EDITOR", filepath.Join(binDir, "editor.cmd"))
951			env.Setenv("USERPROFILE", homeDir)
952			// There is not currently a convenient way to override the shell on
953			// Windows.
954		default:
955			env.Setenv("EDITOR", filepath.Join(binDir, "editor"))
956			env.Setenv("SHELL", filepath.Join(binDir, "shell"))
957		}
958	
959		root := make(map[string]any)
960		switch runtime.GOOS {
961		case "windows":
962			root["/bin"] = map[string]any{
963				// editor.cmd is a non-interactive script that appends "# edited\n"
964				// to the end of each file and creates an empty .edited file in each
965				// directory.
966				"editor.cmd": &vfst.File{
967					Contents: []byte(chezmoitest.JoinLines(
968						`@echo off`,
969						`:loop`,
970						`IF EXIST %~s1\NUL (`,
971						`	copy /y NUL "%~1\.edited" >NUL`,
972						// FIXME recursively edit all files if in a directory
973						`) ELSE (`,
974						`	echo.# edited>>"%~1"`,
975						`)`,
976						`shift`,
977						`IF NOT "%~1"=="" goto loop`,
978					)),
979				},
980			}
981		default:
982			root["/bin"] = map[string]any{
983				// editor is a non-interactive script that appends "# edited\n" to
984				// the end of each file.
985				"editor": &vfst.File{
986					Perm: 0o755,
987					Contents: []byte(chezmoitest.JoinLines(
988						`#!/bin/sh`,
989						``,
990						`for name in $*; do`,
991						`    if [ -d $name ]; then`,
992						`        touch $name/.edited`,
993						`        for filename in $(find $name -type f); do`,
994						`            echo "# edited" >> $filename`,
995						`        done`,
996						`    else`,
997						`        echo "# edited" >> $name`,
998						`    fi`,
999						`done`,
1000					)),
1001				},
1002			}
1003		}
1004	
1005		return vfst.NewBuilder().Build(vfs.NewPathFS(vfs.OSFS, env.WorkDir), root)
1006	}
1007	
1008	// unix2DOS returns data with UNIX line endings converted to DOS line endings.
1009	func unix2DOS(data []byte) ([]byte, error) {
1010		builder := strings.Builder{}
1011		for line := range bytes.Lines(data) {
1012			if _, err := builder.Write(line); err != nil {
1013				return nil, err
1014			}
1015			if _, err := builder.WriteString("\r\n"); err != nil {
1016				return nil, err
1017			}
1018		}
1019		return []byte(builder.String()), nil
1020	}
1021	
1022	func writeNewFile(filename string, data []byte, perm fs.FileMode) error {
1023		switch _, err := os.Lstat(filename); {
1024		case err == nil:
1025			return fmt.Errorf("%s: %w", filename, fs.ErrExist)
1026		case errors.Is(err, fs.ErrNotExist):
1027			return os.WriteFile(filename, data, perm)
1028		default:
1029			return err
1030		}
1031	}
1032	

